  return (
    <form onSubmit={handleSubmit(onSubmit)}>
      <InputField label="姓名" error={errors.name?.message}>
        <input {...register('name')} />
      </InputField>

      <InputField label="邮箱" error={errors.email?.message}>
        <input type="email" {...register('email')} />
      </InputField>

      {/* ... 更多字段 */}

      <button type="submit" disabled={isSubmitting}>
        {isSubmitting ? '提交中...' : '保存'}
